package com.socialblog.follower.application;import com.fasterxml.jackson.databind.ObjectMapper;import com.socialblog.follower.domain.*;import com.socialblog.follower.repository.*;import org.junit.jupiter.api.Test;import java.util.*;import static org.mockito.Mockito.*;class UserEventConsumerTest{@Test void projectsRegistrationOnce()throws Exception{UserProjectionRepository users=mock(UserProjectionRepository.class);ProcessedEventRepository processed=mock(ProcessedEventRepository.class);UUID event=UUID.randomUUID(),user=UUID.randomUUID();when(processed.existsById(event)).thenReturn(false,true);when(users.findById(user)).thenReturn(Optional.empty());UserEventConsumer c=new UserEventConsumer(new ObjectMapper(),users,processed);String raw="{\"eventId\":\""+event+"\",\"eventType\":\"UserRegistered\",\"payload\":{\"userId\":\""+user+"\",\"displayName\":\"Alice\"}}";c.consume(raw);c.consume(raw);verify(users,times(1)).save(argThat(UserProjection::isActive));verify(processed,times(1)).save(any());}}
